[FormDataSourceEventHandler(formDataSourceStr(LedgerJournalTransDaily, LedgerJournalTrans), FormDataSourceEventType::Activated)]
public static void LedgerJournalTrans_OnActivated(FormDataSource sender, FormDataSourceEventArgs e)
{
    FormRun formRun = sender.formRun();
    FormComboBoxControl accountType = formRun.design().controlName(formControlStr(LedgerJournalTransDaily, LedgerJournalTrans_AccountType));
    FormComboBoxControl offsetType  = formRun.design().controlName(formControlStr(LedgerJournalTransDaily, LedgerJournalTrans_OffsetType));

    LedgerJournalTransDailyControl_Eventhandelers::restrictEnumValues(accountType);
    LedgerJournalTransDailyControl_Eventhandelers::restrictEnumValues(offsetType);
}

[FormControlEventHandler(formControlStr(LedgerJournalTransDaily, LedgerJournalTrans_AccountType), FormControlEventType::Enter)]
public static void LedgerJournalTrans_AccountType_OnEnter(FormControl sender, FormControlEventArgs e)
{
    LedgerJournalTransDailyControl_Eventhandelers::restrictEnumValues(sender as FormComboBoxControl);
}

[FormControlEventHandler(formControlStr(LedgerJournalTransDaily, LedgerJournalTrans_OffsetType), FormControlEventType::Enter)]
public static void LedgerJournalTrans_OffsetType_OnEnter(FormControl sender, FormControlEventArgs e)
{
    LedgerJournalTransDailyControl_Eventhandelers::restrictEnumValues(sender as FormComboBoxControl);
}
